function getPlanning3dAreaProfile(areaId = planning3dState?.areaId || "machachi") {
  return planning3dAreaCatalog[areaId] || planning3dAreaCatalog.machachi;
}

function applyPlanning3dAreaProfile(areaId = planning3dState?.areaId || "machachi") {
  const profile = getPlanning3dAreaProfile(areaId);
  planning3dCatalog.buildings.previewDataPath = profile.previewBuildingsPath || profile.buildingsPath;
  planning3dCatalog.buildings.publicDataPath = profile.buildingsPath;
  planning3dCatalog.buildings.publicRecordCount = profile.buildingsCount;
  planning3dCatalog.buildings.description = profile.buildingsDescription;
  planning3dCatalog.parcels.previewDataPath = profile.previewParcelsPath || profile.parcelsPath;
  planning3dCatalog.parcels.publicDataPath = profile.parcelsPath;
  planning3dCatalog.parcels.publicRecordCount = profile.parcelsCount;
  planning3dCatalog.parcels.description = profile.parcelsDescription;
  planning3dPublishedBounds = [...profile.bounds];
  planning3dPublishedView = {
    ...planning3dPublishedView,
    ...profile.view,
  };
  return profile;
}

applyPlanning3dAreaProfile("machachi");

function getPlanning3dViewCamera(mode = planning3dState.viewMode, overrides = {}) {
  const base = {
    center: planning3dPublishedView.center,
    zoom: planning3dPublishedView.zoom,
    pitch: planning3dPublishedView.pitch,
    bearing: planning3dPublishedView.bearing,
  };
  if (mode === "orthographic") {
    return {
      ...base,
      pitch: 0,
      bearing: 0,
      zoom: Math.max(15.4, (base.zoom || 16) - 0.3),
      ...overrides,
    };
  }
  return {
    ...base,
    pitch: Math.max(46, base.pitch || 54),
    bearing: Number.isFinite(base.bearing) ? base.bearing : -14,
    ...overrides,
  };
}

function syncPlanning3dViewButtons() {
  if (dom.planning3dPerspectiveBtn) {
    dom.planning3dPerspectiveBtn.classList.toggle("active", planning3dState.viewMode === "perspective");
  }
  if (dom.planning3dOrthographicBtn) {
    dom.planning3dOrthographicBtn.classList.toggle("active", planning3dState.viewMode === "orthographic");
  }
}

function setPlanning3dViewMode(mode = "perspective", options = {}) {
  planning3dState.viewMode = mode === "orthographic" ? "orthographic" : "perspective";
  syncPlanning3dViewButtons();
  if (!planning3dState.map) {
    return;
  }

  const camera = getPlanning3dViewCamera(planning3dState.viewMode);
  const targetCamera = options.recenter ? camera : {
    ...camera,
    center: planning3dState.map.getCenter(),
    zoom: planning3dState.map.getZoom(),
  };

  const duration = options.duration ?? 620;
  planning3dState.map.easeTo({
    ...targetCamera,
    duration,
    essential: true,
  });
  if (options.recenter) {
    stabilizePlanning3dViewport({ focus: true });
  } else {
    stabilizePlanning3dViewport({ focus: false });
  }
  if (typeof window !== "undefined") {
    window.setTimeout(() => {
      refreshPlanning3dVisualState({ allowRecovery: true, updateSummary: true });
    }, duration + 160);
  }
}

