function renderStudyAreaLayer() {
  if (!mapState.map) {
    return;
  }

  if (mapState.studyAreaLayer) {
    mapState.map.removeLayer(mapState.studyAreaLayer);
    mapState.studyAreaLayer = null;
  }

  mapState.studyAreaLayer = L.geoJSON(getAgronomyAreaFeature(), {
    style: {
      color: "#d6a96f",
      weight: 2,
      fillOpacity: 0,
      dashArray: "6 8",
    },
  }).addTo(mapState.map);
}

function fitAgronomyArea() {
  if (!mapState.map) {
    return;
  }

  const areaFeature = getAgronomyAreaFeature();
  const areaLayer = L.geoJSON(areaFeature);
  mapState.map.fitBounds(areaLayer.getBounds(), {
    padding: [28, 28],
    maxZoom: getAgronomyAreaMapView().zoom,
  });
}

function refreshVisibleGeoLayers(layerIds = null) {
  if (!mapState.map || !dom.layersTree) {
    return;
  }

  const allowed = Array.isArray(layerIds) ? new Set(layerIds) : null;
  Array.from(dom.layersTree.querySelectorAll("input[data-layer]")).forEach((input) => {
    const layerId = input.dataset.layer;
    if (!input.checked) {
      return;
    }
    if (allowed && !allowed.has(layerId)) {
      return;
    }
    const key = layerKey(layerId);
    if (mapState[key]) {
      mapState.map.removeLayer(mapState[key]);
      mapState[key] = null;
    }
  });

  updateLayerVisibility();
}

async function setAgronomyArea(areaId = state.agronomyAreaId, options = {}) {
  const nextAreaId = agronomyAreaCatalog[areaId] ? areaId : "mejia";
  const changed = state.agronomyAreaId !== nextAreaId;
  const hadInamhiReadout = dom.inamhiResults?.classList.contains("has-data");
  const hadInamhiLiveReadout = dom.inamhiLiveResults?.classList.contains("has-data");
  const hadHydroReadout = dom.hydroNetworkResults?.classList.contains("has-data");
  const hadSuitabilityReadout = dom.agroSuitabilityResults?.classList.contains("has-data");
  state.agronomyAreaId = nextAreaId;

  syncAgronomyAreaUi();
  syncEntryRouteUi(state.entryRoute);
  if (state.gpsSender.open) {
    renderGpsSenderContext();
    renderGpsSenderLinks();
  }

  if (changed || options.forceReset) {
    resetAgronomySelectionState();
  }

  if (mapState.map) {
    renderStudyAreaLayer();
    refreshVisibleGeoLayers(["parroquias", "vias", "rios", "acequias", "quebradas", "lotes", "estaciones"]);
    if (options.fit !== false) {
      fitAgronomyArea();
    }
  }

  if (options.fetchScenes !== false) {
    await filterSentinelImages();
  }

  if (hadInamhiReadout || options.refreshInamhi) {
    await runInamhiAnalysis(true);
  }
  if (hadInamhiLiveReadout) {
    await runInamhiLiveAnalysis(true);
  }
  if (hadHydroReadout || (state.entryRoute === "agronomia" && options.autoHydro !== false)) {
    await runHydroNetworkAnalysis(true);
  }
  if (hadSuitabilityReadout) {
    await runAgroSuitabilityAnalysis(true);
  }

  if (!options.silent && changed) {
      setStatus(`Ambito agronomico ajustado a ${getAgronomyAreaProfile().scopeLabel}. Ya puedes consultar escenas, lotes demo y analisis.`);
  }

  return changed;
}

