    projection: "EPSG:32717",
    viaBackend: false,
    buildings: {
      available: true,
      label: planning3dCatalog.buildings.label,
      basePath: planning3dCatalog.buildings.basePath,
      recordCount: planning3dCatalog.buildings.publicRecordCount || null,
      stats: null,
    },
