function createTerritorialBufferFeature(feature, distanceKm, properties = {}) {
  if (!feature?.geometry || !Number.isFinite(distanceKm) || distanceKm <= 0) {
    return null;
  }

  try {
    const buffered = turf.buffer(feature, distanceKm, { units: "kilometers" });
    if (!buffered?.geometry) {
      return null;
    }
    buffered.properties = {
      ...(feature.properties || {}),
      ...properties,
      bufferKm: Number(distanceKm.toFixed(2)),
    };
    return buffered;
  } catch (error) {
    return null;
  }
}

function getPlanningCoverageProfile(programId) {
  const profiles = {
    vis: [
      { km: 0.9, label: "Halo residencial extendido", zone: "outer" },
      { km: 0.55, label: "Cobertura barrial", zone: "mid" },
      { km: 0.22, label: "Nucleo de implantacion", zone: "inner" },
    ],
    escuela: [
      { km: 1.4, label: "Cobertura educativa extendida", zone: "outer" },
      { km: 0.82, label: "Cobertura caminable", zone: "mid" },
      { km: 0.28, label: "Nucleo escolar", zone: "inner" },
    ],
    hospital: [
      { km: 2.2, label: "Radio de referencia sanitaria", zone: "outer" },
      { km: 1.24, label: "Acceso estrategico", zone: "mid" },
      { km: 0.42, label: "Nucleo hospitalario", zone: "inner" },
    ],
    equipamiento: [
      { km: 0.8, label: "Area de influencia barrial", zone: "outer" },
      { km: 0.44, label: "Cobertura de proximidad", zone: "mid" },
      { km: 0.18, label: "Nucleo barrial", zone: "inner" },
    ],
  };
  return profiles[programId] || profiles.vis;
}

function buildPlanningFootprintFeatures(planning) {
  return planning.candidates
    .map((candidate) => {
      const feature = cloneFeature(candidate.feature);
      if (!feature?.geometry) {
        return null;
      }
      feature.properties = {
        ...(feature.properties || {}),
        candidateId: candidate.id,
        candidateRank: candidate.rank,
        title: candidate.title,
        score: candidate.score,
        summary: candidate.summary,
      };
      return feature;
    })
    .filter(Boolean);
}

function buildPlanningCoverageFeatures(planning) {
  const profile = getPlanningCoverageProfile(planning.program.id);
  const features = [];

  planning.candidates.forEach((candidate) => {
    profile.forEach((ring, index) => {
      const buffered = createTerritorialBufferFeature(candidate.feature, ring.km, {
        candidateId: candidate.id,
        candidateRank: candidate.rank,
        title: candidate.title,
        score: candidate.score,
        summary: candidate.summary,
        coverageLabel: ring.label,
        coverageZone: ring.zone,
        coverageLevel: index,
      });
      if (buffered) {
        features.push(buffered);
      }
    });
  });

  return {
    type: "FeatureCollection",
    features,
  };
}

function buildLandChangeHeatFeatures(analysis) {
  const features = [];
  const multiplier = Number(analysis?.scenario?.growthMultiplier) || 1;

  analysis.prioritySectors.forEach((sector) => {
    const ringDistances = [
      0.44 * multiplier,
      0.24 * multiplier,
    ];

    ringDistances.forEach((distanceKm, index) => {
      const buffered = createTerritorialBufferFeature(sector.feature, distanceKm, {
        landChangeSectorId: sector.id,
        rank: sector.rank,
        name: sector.name,
        score: sector.score,
        pressureLabel: sector.pressureLabel,
        summary: sector.summary,
        heatZone: index === 0 ? "outer" : "inner",
        heatLevel: index,
      });
      if (buffered) {
        features.push(buffered);
      }
    });
  });

  return {
    type: "FeatureCollection",
    features,
  };
}

function getHydrologyBufferProfile(sector) {
  const roleLabel = String(sector?.role || "").toLowerCase();
  if (roleLabel.includes("recarga")) {
    return {
      kind: "protection",
      label: "Franja de proteccion de recarga",
      rings: [0.54, 0.28],
    };
  }
  if ((sector?.floodRisk || 0) >= (sector?.droughtRisk || 0)) {
    return {
      kind: "flood",
      label: "Franja de vigilancia por crecida",
      rings: [0.48, 0.24],
    };
  }
  return {
    kind: "stress",
    label: "Franja de gestion por estiaje",
    rings: [0.46, 0.22],
  };
}

function buildHydrologyBufferFeatures(hydrology) {
  const features = [];

  hydrology.prioritySectors.forEach((sector) => {
    const profile = getHydrologyBufferProfile(sector);
    const scale = clamp((sector.stressScore || 0) / 100, 0.62, 1.18);

    profile.rings.forEach((distanceKm, index) => {
      const buffered = createTerritorialBufferFeature(sector.feature, distanceKm * scale, {
        hydrologySectorId: sector.id,
        rank: sector.rank,
        name: sector.name,
        summary: sector.summary,
        balanceLabel: sector.balanceLabel,
        resilience: sector.resilience,
        bufferKind: profile.kind,
        bufferLabel: profile.label,
        bufferLevel: index,
      });
      if (buffered) {
        features.push(buffered);
      }
    });
  });

  return {
    type: "FeatureCollection",
    features,
  };
}

function renderFodaCameOverlay(analysis) {
  clearFodaCameOverlay();
  if (!mapState.map) {
    return;
  }

  mapState.fodaCameZoneLayer = L.geoJSON(analysis.zoneSurface, {
    style: (feature) => {
      const actionId = feature.properties?.cameId || "mantener";
      const active = feature.properties?.zoneId === state.fodaCameHighlightId;
      const palette = getFodaCameOverlayPalette(actionId);
      return {
        color: active ? "#fff6ea" : palette.stroke,
        weight: active ? 2.2 : 1.15,
        fillColor: palette.fill,
        fillOpacity: active ? 0.32 : 0.18,
        dashArray: active ? null : palette.dashArray,
      };
    },
    onEachFeature: (feature, layer) => {
      layer.bindPopup(
        `<h3 class="popup-title">${feature.properties?.zoneTitle || "Zona estrategica"}</h3><p class="popup-copy">${feature.properties?.summary || ""} FODA: ${feature.properties?.swotLabel || "sin lectura"} | CAME: ${feature.properties?.cameLabel || "sin accion"}.</p>`
      );
    },
  }).addTo(mapState.map);

  mapState.fodaCamePriorityLayer = L.geoJSON({
    type: "FeatureCollection",
    features: analysis.priorityZones.map((zone) => cloneFeature(zone.feature)),
  }, {
    style: (feature) => ({
      color: feature.properties?.zoneId === state.fodaCameHighlightId ? "#fff7ef" : "#f5efe4",
      weight: feature.properties?.zoneId === state.fodaCameHighlightId ? 2.8 : 2,
      fillColor: "transparent",
      fillOpacity: 0,
      dashArray: "5 6",
    }),
    onEachFeature: (feature, layer) => {
      layer.bindPopup(
        `<h3 class="popup-title">${feature.properties?.zoneTitle || "Zona prioritaria"}</h3><p class="popup-copy">${feature.properties?.summary || ""}</p>`
      );
    },
  }).addTo(mapState.map);

  mapState.fodaCameZoneLayer?.bringToBack?.();
  mapState.fodaCamePriorityLayer?.bringToFront?.();
  if (mapState.currentPlotLayer) {
    mapState.currentPlotLayer.bringToFront();
  }
  if (state.aiGeoData?.mode === "territorial") {
    bringAiGeoOverlayToFront();
  }
}

function getFodaCameOverlayPalette(actionId = "mantener") {
  const palettes = {
    mantener: {
      stroke: "#397f5f",
      fill: "#78be96",
      dashArray: null,
    },
    explotar: {
      stroke: "#c28a34",
      fill: "#f2cf77",
      dashArray: "8 6",
    },
    corregir: {
      stroke: "#bf6d35",
      fill: "#e3a16b",
      dashArray: "6 6",
    },
    afrontar: {
      stroke: "#a5544b",
      fill: "#d98f83",
      dashArray: "4 6",
    },
  };
  return palettes[actionId] || palettes.mantener;
}

function renderPlanningOverlay(planning) {
  clearPlanningOverlay();
  if (!mapState.map) {
    return;
  }

  const coverageCollection = buildPlanningCoverageFeatures(planning);
  const footprintCollection = {
    type: "FeatureCollection",
    features: buildPlanningFootprintFeatures(planning),
  };
  const restrictionCollection = planning.restrictions?.collection || { type: "FeatureCollection", features: [] };
  const serviceCoverageCollection = planning.serviceCoverage?.bufferCollection || { type: "FeatureCollection", features: [] };
  const serviceGapCollection = planning.serviceCoverage?.gapCollection || { type: "FeatureCollection", features: [] };
  const serviceFacilityCollection = planning.serviceCoverage?.facilityCollection || { type: "FeatureCollection", features: [] };
  const solarCollection = planning.solarReadout?.shadowCollection || { type: "FeatureCollection", features: [] };
  const candidatePoints = planning.candidates.map((candidate) => pointFeature(candidate.title, candidate.centroid, {
    candidateId: candidate.id,
    candidateRank: candidate.rank,
    score: candidate.score,
    summary: candidate.summary,
  }));

  if (coverageCollection.features.length) {
    mapState.planningCoverageLayer = L.geoJSON(coverageCollection, {
      style: (feature) => {
        const active = feature.properties?.candidateId === state.planningHighlightId;
        const zone = feature.properties?.coverageZone || "outer";
        const fillOpacity = zone === "inner"
          ? (active ? 0.16 : 0.1)
          : zone === "mid"
            ? (active ? 0.11 : 0.07)
            : (active ? 0.08 : 0.045);
        return {
          color: planning.program.markerColor,
          weight: zone === "inner" ? 1.3 : 1,
          fillColor: planning.program.markerColor,
          fillOpacity,
          dashArray: zone === "inner" ? null : "8 8",
        };
      },
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.title || "Cobertura territorial"}</h3><p class="popup-copy">${feature.properties?.coverageLabel || "Franja de influencia"} a ${feature.properties?.bufferKm || 0} km para ${planning.program.longLabel.toLowerCase()}. Puntaje ${feature.properties?.score || 0}/100.</p>`
        );
      },
    }).addTo(mapState.map);
  }

  if (restrictionCollection.features.length) {
    mapState.planningRestrictionLayer = L.geoJSON(restrictionCollection, {
      style: (feature) => {
        const tone = feature.properties?.restrictionTone || "land";
        const palette = tone === "critical"
          ? { stroke: "#b35a47", fill: "#e0a08e" }
          : tone === "resilience"
          ? { stroke: "#4c8eab", fill: "#8fd9e0" }
          : tone === "service"
            ? { stroke: "#cb9440", fill: "#efc36b" }
            : tone === "base"
              ? { stroke: "#6b7380", fill: "#c9d0da" }
            : { stroke: "#7f6a4f", fill: "#d7bb8b" };
        return {
          color: palette.stroke,
          weight: tone === "critical" ? 1.4 : 1.1,
          fillColor: palette.fill,
          fillOpacity: tone === "critical" ? 0.16 : 0.12,
          dashArray: tone === "critical" ? "4 5" : "6 6",
        };
      },
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.restrictionLabel || "Restriccion territorial"}</h3><p class="popup-copy">${feature.properties?.restrictionCopy || "Condicion territorial activa para ordenar ocupacion."}</p>`
        );
      },
    }).addTo(mapState.map);
  }

  if (serviceCoverageCollection.features.length) {
    mapState.planningServiceLayer = L.geoJSON(serviceCoverageCollection, {
      style: (feature) => ({
        color: feature.properties?.coverageColor || "#5d8f62",
        weight: feature.properties?.coverageZone === "walk" ? 1.4 : feature.properties?.coverageZone === "support" ? 1.1 : 0.95,
        fillColor: feature.properties?.coverageColor || "#5d8f62",
        fillOpacity: feature.properties?.coverageZone === "walk" ? 0.11 : feature.properties?.coverageZone === "support" ? 0.08 : 0.05,
        dashArray: feature.properties?.coverageZone === "walk" ? null : "8 8",
      }),
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.coverageLabel || "Cobertura de servicio"}</h3><p class="popup-copy">${feature.properties?.isochroneLabel || "Radio funcional"} con ${feature.properties?.coveragePct || 0}% de cobertura y brecha restante ${feature.properties?.coverageGapPct || 0}%.</p>`
        );
      },
    }).addTo(mapState.map);
  }

  if (serviceGapCollection.features.length) {
    mapState.planningServiceGapLayer = L.geoJSON(serviceGapCollection, {
      pointToLayer: (feature, latlng) => L.circleMarker(latlng, {
        radius: 6.2,
        weight: 2.4,
        color: "#fff7ee",
        fillColor: feature.properties?.coverageColor || "#d39a3d",
        fillOpacity: 0.98,
      }),
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.deficitLabel || "Deficit de servicio"}</h3><p class="popup-copy">${feature.properties?.summary || "Sector con brecha funcional y demanda territorial."}</p>`
        );
      },
    }).addTo(mapState.map);
  }

  if (serviceFacilityCollection.features.length) {
    mapState.planningFacilityLayer = L.geoJSON(serviceFacilityCollection, {
      pointToLayer: (feature, latlng) => L.circleMarker(latlng, {
        radius: 5.5,
        weight: 2,
        color: "#fff8ef",
        fillColor: feature.properties?.coverageColor || "#5d8f62",
        fillOpacity: 0.95,
      }),
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.name || "Equipamiento"}</h3><p class="popup-copy">${feature.properties?.coverageLabel || "Cobertura activa"} desde ${feature.properties?.name || "el equipamiento"}.</p>`
        );
      },
    }).addTo(mapState.map);
  }

  if (solarCollection.features.length) {
    mapState.planningSolarLayer = L.geoJSON(solarCollection, {
      style: {
        color: "#6a5040",
        weight: 2.2,
        opacity: 0.75,
        dashArray: "10 8",
      },
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.label || "Lectura solar"}</h3><p class="popup-copy">${feature.properties?.solarSignal || "Asoleamiento"} con sombra estimada de ${feature.properties?.shadowLengthM || 0} m y ${feature.properties?.sunHours || 0} horas utiles de sol.</p>`
        );
      },
    }).addTo(mapState.map);
  }

  if (footprintCollection.features.length) {
    mapState.planningLayer = L.geoJSON(footprintCollection, {
      style: (feature) => {
        const active = feature.properties?.candidateId === state.planningHighlightId;
        return {
          color: active ? "#fff7ef" : planning.program.markerColor,
          weight: active ? 2.4 : 1.5,
          fillColor: planning.program.markerColor,
          fillOpacity: active ? 0.26 : 0.14,
          dashArray: active ? null : "5 5",
        };
      },
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.title || "Sector candidato"}</h3><p class="popup-copy">${feature.properties?.summary || ""} Delimitacion priorizada para ${planning.program.longLabel.toLowerCase()} con puntaje ${feature.properties?.score || 0}/100.</p>`
        );
      },
    }).addTo(mapState.map);
  }

  mapState.planningCandidatesLayer = L.geoJSON({
    type: "FeatureCollection",
    features: candidatePoints,
  }, {
    pointToLayer: (feature, latlng) => {
      const active = feature.properties?.candidateId === state.planningHighlightId;
      return L.circleMarker(latlng, {
        radius: active ? 9 : 7,
        weight: 2.6,
        color: active ? "#fff6ea" : "#f7f2e8",
        fillColor: planning.program.markerColor,
        fillOpacity: active ? 1 : 0.88,
      });
    },
    onEachFeature: (feature, layer) => {
      layer.bindPopup(
        `<h3 class="popup-title">${feature.properties.name || "Candidato"}</h3><p class="popup-copy">${feature.properties.summary} Puntaje ${feature.properties.score}/100.</p>`
      );
    },
  }).addTo(mapState.map);

  if (mapState.planningCoverageLayer?.bringToBack) {
    mapState.planningCoverageLayer.bringToBack();
  }
  if (mapState.planningRestrictionLayer?.bringToFront) {
    mapState.planningRestrictionLayer.bringToFront();
  }
  if (mapState.planningServiceLayer?.bringToFront) {
    mapState.planningServiceLayer.bringToFront();
  }
  if (mapState.planningSolarLayer?.bringToFront) {
    mapState.planningSolarLayer.bringToFront();
  }
  if (mapState.planningLayer?.bringToFront) {
    mapState.planningLayer.bringToFront();
  }
  if (mapState.planningFacilityLayer?.bringToFront) {
    mapState.planningFacilityLayer.bringToFront();
  }
  if (mapState.planningServiceGapLayer?.bringToFront) {
    mapState.planningServiceGapLayer.bringToFront();
  }
  if (mapState.currentPlotLayer) {
    mapState.currentPlotLayer.bringToFront();
  }
  if (mapState.managementLayer) {
    mapState.managementLayer.bringToFront();
  }
  if (mapState.planningCandidatesLayer?.bringToFront) {
    mapState.planningCandidatesLayer.bringToFront();
  }
  if (state.aiGeoData?.mode === "territorial") {
    bringAiGeoOverlayToFront();
  }
}

function renderLandChangeOverlay(analysis) {
  clearLandChangeOverlay();
  if (!mapState.map) {
    return;
  }

  const heatCollection = buildLandChangeHeatFeatures(analysis);

  mapState.landChangeLayer = L.geoJSON(analysis.surface, {
    style: (feature) => {
      const classId = feature.properties?.classId;
      if (classId === "base2010" || classId === "base2016" || classId === "base2022") {
        return {
          color: "#f7f2e8",
          weight: 1.3,
          fillColor: classId === "base2016" ? "#ff5a36" : classId === "base2022" ? "#ff4a34" : "#ff3a2d",
          fillOpacity: 0.72,
        };
      }
      if (classId === "growth2016") {
        return {
          color: "#ffe8c7",
          weight: 1.2,
          fillColor: "#ff9314",
          fillOpacity: 0.82,
        };
      }
      if (classId === "growth2022") {
        return {
          color: "#fff4db",
          weight: 1.2,
          fillColor: "#ffc72b",
          fillOpacity: 0.84,
        };
      }
      return {
        color: "#f5efe4",
        weight: 1.6,
        fillColor: "#f8dd83",
        fillOpacity: 0.18,
        dashArray: "6 6",
      };
    },
    onEachFeature: (feature, layer) => {
      layer.bindPopup(
        `<h3 class="popup-title">${feature.properties?.settlementName || feature.properties?.name || "Huella urbana"}</h3><p class="popup-copy">${feature.properties?.stageLabel || "Serie de huella"} sobre ${feature.properties?.settlementName || "Mejia"}${feature.properties?.areaHa ? ` con ${formatLandChangeHa(feature.properties.areaHa)} ha.` : "."}</p>`
      );
      layer.bindTooltip(
        `${feature.properties?.stageLabel || "Huella"} | ${feature.properties?.settlementName || "Mejia"}`,
        { sticky: true }
      );
    },
  }).addTo(mapState.map);

  if (analysis.pressureSurface?.features?.length) {
    const visiblePressureCollection = {
      type: "FeatureCollection",
      features: analysis.pressureSurface.features.filter((feature) => {
        const surfaceType = feature.properties?.surfaceType;
        return surfaceType !== "quebrada" && surfaceType !== "evidencia" && surfaceType !== "sensible";
      }),
    };
    if (visiblePressureCollection.features.length) {
    mapState.landChangePressureLayer = L.geoJSON(visiblePressureCollection, {
      style: (feature) => {
        const surfaceType = feature.properties?.surfaceType;
        if (surfaceType === "quebrada" || surfaceType === "evidencia") {
          return {
            color: surfaceType === "evidencia" ? "#4c8eab" : "#58aec2",
            weight: surfaceType === "evidencia" ? 2 : 1.8,
            fillColor: surfaceType === "evidencia" ? "#9fd9e1" : "#8fd9e0",
            fillOpacity: surfaceType === "evidencia" ? 0.16 : 0.12,
            dashArray: "8 6",
          };
        }
        if (surfaceType === "sensible") {
          return {
            color: "#c78b42",
            weight: 1.6,
            fillColor: "#efc96e",
            fillOpacity: 0.12,
            dashArray: "6 10",
          };
        }
        return {
          color: "#8a6a4f",
          weight: 1.4,
          fillColor: "#d8bb91",
          fillOpacity: 0.08,
          dashArray: "6 8",
        };
      },
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.name || "Corredor territorial"}</h3><p class="popup-copy">${feature.properties?.summary || "Franja de presion territorial para lectura preventiva."}</p>`
        );
      },
    }).addTo(mapState.map);
    }
  }

  if (heatCollection.features.length) {
    mapState.landChangeHeatLayer = L.geoJSON(heatCollection, {
      style: (feature) => {
        const active = feature.properties?.landChangeSectorId === state.landChangeHighlightId;
        const zone = feature.properties?.heatZone || "outer";
        return {
          color: zone === "inner" ? "#c45f1c" : "#ff9724",
          weight: zone === "inner" ? 1.2 : 0.9,
          fillColor: zone === "inner" ? "#ff7b3f" : "#ffb347",
          fillOpacity: zone === "inner"
            ? (active ? 0.18 : 0.12)
            : (active ? 0.12 : 0.07),
          dashArray: zone === "inner" ? null : "8 8",
        };
      },
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.name || "Hotspot territorial"}</h3><p class="popup-copy">${feature.properties?.pressureLabel || "Presion territorial"} con halo ${feature.properties?.heatZone === "inner" ? "intensivo" : "extendido"} a ${feature.properties?.bufferKm || 0} km. Puntaje ${feature.properties?.score || 0}/100.</p>`
        );
      },
    }).addTo(mapState.map);
  }

  const hotspotPoints = analysis.prioritySectors.map((sector) => pointFeature(sector.name, sector.centroid, {
    landChangeSectorId: sector.id,
    rank: sector.rank,
    score: sector.score,
    pressureLabel: sector.pressureLabel,
    summary: sector.summary,
  }));

  mapState.landChangeHotspotLayer = L.geoJSON({
    type: "FeatureCollection",
    features: hotspotPoints,
  }, {
    pointToLayer: (feature, latlng) => {
      const active = feature.properties?.landChangeSectorId === state.landChangeHighlightId;
      return L.circleMarker(latlng, {
        radius: active ? 9 : 7,
        weight: 2.4,
        color: active ? "#fff8eb" : "#fff1d5",
        fillColor: active ? "#cc6b18" : "#ff9a1f",
        fillOpacity: 0.96,
      });
    },
    onEachFeature: (feature, layer) => {
      layer.bindPopup(
        `<h3 class="popup-title">${feature.properties?.name || "Hotspot"}</h3><p class="popup-copy">${feature.properties?.summary || ""} Puntaje ${feature.properties?.score || 0}/100.</p>`
      );
    },
  }).addTo(mapState.map);

  if (mapState.landChangePressureLayer?.bringToBack) {
    mapState.landChangePressureLayer.bringToBack();
  }
  if (mapState.landChangeHeatLayer?.bringToFront) {
    mapState.landChangeHeatLayer.bringToFront();
  }
  if (mapState.landChangeLayer?.bringToFront) {
    mapState.landChangeLayer.bringToFront();
  }
  if (mapState.landChangeHotspotLayer?.bringToFront) {
    mapState.landChangeHotspotLayer.bringToFront();
  }
  if (mapState.hydrologyPriorityLayer?.bringToFront) {
    mapState.hydrologyPriorityLayer.bringToFront();
  }
  if (mapState.planningCandidatesLayer?.bringToFront) {
    mapState.planningCandidatesLayer.bringToFront();
  }
  if (state.aiGeoData?.mode === "territorial") {
    bringAiGeoOverlayToFront();
  }
}

function renderHydrologyOverlay(hydrology) {
  clearHydrologyOverlay();
  if (!mapState.map) {
    return;
  }

  const bufferCollection = buildHydrologyBufferFeatures(hydrology);

  if (bufferCollection.features.length) {
    mapState.hydrologyBufferLayer = L.geoJSON(bufferCollection, {
      style: (feature) => {
        const active = feature.properties?.hydrologySectorId === state.hydrologyHighlightId;
        const kind = feature.properties?.bufferKind || "stress";
        const level = feature.properties?.bufferLevel || 0;
        const palette = kind === "protection"
          ? { stroke: "#2f7f5f", fill: "#7fc7a1" }
          : kind === "flood"
            ? { stroke: "#4c8eab", fill: "#8fd9e0" }
            : { stroke: "#cb9440", fill: "#efc36b" };
        return {
          color: palette.stroke,
          weight: level === 0 ? 1 : 1.3,
          fillColor: palette.fill,
          fillOpacity: level === 0
            ? (active ? 0.12 : 0.08)
            : (active ? 0.17 : 0.11),
          dashArray: level === 0 ? "8 8" : null,
        };
      },
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.name || "Franja hidrica"}</h3><p class="popup-copy">${feature.properties?.bufferLabel || "Franja hidrica"} a ${feature.properties?.bufferKm || 0} km. ${feature.properties?.summary || ""}</p>`
        );
      },
    }).addTo(mapState.map);
  }

  mapState.hydrologyLayer = L.geoJSON(hydrology.surface, {
    style: (feature) => {
      const balanceHm3 = Number(feature.properties?.balanceHm3 || 0);
      const tone = getHydrologyBalanceTone(balanceHm3);
      return {
        color: tone === "surplus" ? "#2b7564" : tone === "watch" ? "#b27c33" : "#9f5441",
        weight: feature.properties?.sectorId === state.hydrologyHighlightId ? 2.4 : 1.6,
        fillColor: tone === "surplus" ? "#72b89a" : tone === "watch" ? "#e2b66a" : "#d38a74",
        fillOpacity: feature.properties?.sectorId === state.hydrologyHighlightId ? 0.34 : 0.24,
        dashArray: feature.properties?.sectorId === state.hydrologyHighlightId ? null : "5 6",
      };
    },
    onEachFeature: (feature, layer) => {
      layer.bindPopup(
        `<h3 class="popup-title">${feature.properties?.name || "Subzona hidrica"}</h3><p class="popup-copy">${feature.properties?.summary || ""} Oferta ${formatHydrologyHm3(feature.properties?.supplyHm3)} hm3/anio, demanda ${formatHydrologyHm3(feature.properties?.demandHm3)} hm3/anio, balance ${feature.properties?.balanceHm3 >= 0 ? "+" : ""}${formatHydrologyHm3(feature.properties?.balanceHm3)} hm3.</p>`
      );
      layer.bindTooltip(
        `${feature.properties?.name || "Subzona"} | ${feature.properties?.balanceLabel || "Balance"} | Resiliencia ${feature.properties?.resilience || 0}/100`,
        { sticky: true }
      );
    },
  }).addTo(mapState.map);

  const priorityPoints = hydrology.prioritySectors.map((sector) => pointFeature(sector.name, sector.centroid, {
    hydrologySectorId: sector.id,
    rank: sector.rank,
    balanceLabel: sector.balanceLabel,
    resilience: sector.resilience,
    summary: sector.summary,
  }));

  mapState.hydrologyPriorityLayer = L.geoJSON({
    type: "FeatureCollection",
    features: priorityPoints,
  }, {
    pointToLayer: (feature, latlng) => {
      const active = feature.properties?.hydrologySectorId === state.hydrologyHighlightId;
      return L.circleMarker(latlng, {
        radius: active ? 9 : 7,
        weight: 2.4,
        color: active ? "#fff6ea" : "#eef8f5",
        fillColor: active ? "#2f7f5f" : "#4c8e79",
        fillOpacity: 0.96,
      });
    },
    onEachFeature: (feature, layer) => {
      layer.bindPopup(
        `<h3 class="popup-title">${feature.properties?.name || "Prioridad hidrica"}</h3><p class="popup-copy">${feature.properties?.summary || ""}</p>`
      );
    },
  }).addTo(mapState.map);

  if (mapState.hydrologyLayer?.bringToBack) {
    mapState.hydrologyLayer.bringToBack();
  }
  if (mapState.hydrologyBufferLayer?.bringToFront) {
    mapState.hydrologyBufferLayer.bringToFront();
  }
  if (mapState.hydrologyPriorityLayer?.bringToFront) {
    mapState.hydrologyPriorityLayer.bringToFront();
  }
  if (mapState.planningCandidatesLayer?.bringToFront) {
    mapState.planningCandidatesLayer.bringToFront();
  }
  if (state.aiGeoData?.mode === "territorial") {
    bringAiGeoOverlayToFront();
  }
}

function renderFieldEvidenceOverlay(analysis) {
  clearFieldEvidenceOverlay();
  if (!mapState.map) {
    return;
  }

  const activeType = state.fieldEvidenceHighlightType;
  const activeId = state.fieldEvidenceHighlightId;
  const getSensitivePalette = (tone) => {
    if (tone === "high") {
      return {
        stroke: "#b35a47",
        fill: "#e0a08e",
      };
    }
    if (tone === "mid") {
      return {
        stroke: "#b88444",
        fill: "#ebc471",
      };
    }
    if (tone === "service") {
      return {
        stroke: "#4b88aa",
        fill: "#8fd5df",
      };
    }
    if (tone === "resilience") {
      return {
        stroke: "#2f7f5f",
        fill: "#7fc7a1",
      };
    }
    return {
      stroke: "#6b7380",
      fill: "#c9d0da",
    };
  };

  if (analysis.historyCollection?.features?.length) {
    mapState.fieldEvidenceHistoryLayer = L.geoJSON(analysis.historyCollection, {
      style: (feature) => {
        const highlighted = activeType === "history"
          && String(feature.id || feature.properties?.name) === String(activeId);
        const tone = feature.properties?.sourceGroup === "mdt_historico"
          ? { stroke: "#5c7f95", fill: "#b8d1df" }
          : { stroke: "#b88444", fill: "#ead09c" };
        return {
          color: tone.stroke,
          weight: highlighted ? 2.2 : 1.2,
          fillColor: tone.fill,
          fillOpacity: highlighted ? 0.16 : 0.09,
          dashArray: feature.properties?.sourceKind === "carta_historica" ? "8 8" : "10 6",
        };
      },
      pointToLayer: (feature, latlng) => {
        const highlighted = activeType === "history"
          && String(feature.id || feature.properties?.name) === String(activeId);
        return L.circleMarker(latlng, {
          radius: highlighted ? 8 : 6,
          weight: 2.2,
          color: "#fff6ea",
          fillColor: feature.properties?.sourceGroup === "mdt_historico" ? "#5c7f95" : "#b88444",
          fillOpacity: 0.96,
        });
      },
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.name || "Fuente historica"}</h3><p class="popup-copy">${feature.properties?.summary || "Cobertura historica disponible para soporte territorial."}</p>`
        );
      },
    }).addTo(mapState.map);
  }

  if (analysis.sectorsCollection?.features?.length) {
    mapState.fieldEvidenceSectorLayer = L.geoJSON(analysis.sectorsCollection, {
      style: (feature) => {
        const highlighted = activeType === "sector"
          && String(feature.id || feature.properties?.name) === String(activeId);
        return {
          color: highlighted ? "#1e725e" : "#2f7f5f",
          weight: highlighted ? 2.5 : 1.6,
          fillColor: feature.properties?.hasOrthomosaic && feature.properties?.hasDtm ? "#7fc7a1" : "#9ecfb0",
          fillOpacity: highlighted ? 0.2 : 0.12,
          dashArray: feature.properties?.hasOrthomosaic && feature.properties?.hasDtm ? null : "8 8",
        };
      },
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.sectorLabel || feature.properties?.name || "Sector de campo"}</h3><p class="popup-copy">${feature.properties?.summary || "Sector de campo disponible para soporte territorial."} ${formatLandChangeHa(feature.properties?.coverageHa || 0)} ha | ${feature.properties?.rasterCount || 0} rasters.</p>`
        );
        layer.bindTooltip(
          `${feature.properties?.sectorType || "Sector"} | ${feature.properties?.sectorLabel || feature.properties?.name || "Campo"}`,
          { sticky: true }
        );
      },
    }).addTo(mapState.map);
  }

  if (analysis.sensitiveCollection?.features?.length) {
    mapState.fieldEvidenceSensitiveLayer = L.geoJSON(analysis.sensitiveCollection, {
      style: (feature) => {
        const featureId = feature.properties?.sensitiveThemeId || feature.id;
        const highlighted = activeType === "sensitive"
          && String(featureId) === String(activeId);
        const palette = getSensitivePalette(feature.properties?.sensitiveTone);
        const renderMode = feature.properties?.renderMode || "union";
        return {
          color: palette.stroke,
          weight: highlighted
            ? (renderMode === "envelope" ? 2.4 : 2.8)
            : (renderMode === "envelope" ? 1.4 : 1.9),
          fillColor: palette.fill,
          fillOpacity: renderMode === "envelope"
            ? (highlighted ? 0.12 : 0.06)
            : (highlighted ? 0.24 : 0.14),
          dashArray: renderMode === "envelope" ? "10 8" : null,
          lineCap: "round",
          lineJoin: "round",
        };
      },
      pointToLayer: (feature, latlng) => {
        const featureId = feature.properties?.sensitiveThemeId || feature.id;
        const highlighted = activeType === "sensitive"
          && String(featureId) === String(activeId);
        const palette = getSensitivePalette(feature.properties?.sensitiveTone);
        return L.circleMarker(latlng, {
          radius: highlighted ? 8.5 : 6.8,
          weight: 2.2,
          color: "#fff6ea",
          fillColor: palette.stroke,
          fillOpacity: 0.96,
        });
      },
      onEachFeature: (feature, layer) => {
        const themeLabel = feature.properties?.sensitiveThemeLabel || feature.properties?.name || "Area sensible";
        const groupLabel = feature.properties?.sensitiveGroup || "Procedimiento tecnico";
        const featureCount = Number(feature.properties?.featureCount || 0);
        const renderMode = feature.properties?.renderMode === "envelope" ? "envolvente operativa" : "geometria integrada";
        layer.bindPopup(
          `<h3 class="popup-title">${themeLabel}</h3><p class="popup-copy">${feature.properties?.summary || "Tema sensible integrado desde la consultoria tecnica."} Grupo ${groupLabel.toLowerCase()}, ${featureCount} elementos y ${renderMode} para despliegue web.</p>`
        );
        layer.bindTooltip(
          `${groupLabel} | ${themeLabel} | ${featureCount} elem.`,
          { sticky: true }
        );
      },
    }).addTo(mapState.map);
  }

  if (analysis.stationCollection?.features?.length) {
    mapState.fieldEvidenceStationLayer = L.geoJSON(analysis.stationCollection, {
      pointToLayer: (feature, latlng) => {
        const highlighted = activeType === "station"
          && String(feature.id || feature.properties?.code || feature.properties?.name) === String(activeId);
        const isFlow = feature.properties?.stationKind === "caudal";
        return L.circleMarker(latlng, {
          radius: highlighted ? 8.4 : 6.8,
          weight: 2.4,
          color: "#fff7ee",
          fillColor: isFlow ? "#4f89aa" : "#5c9869",
          fillOpacity: 0.98,
        });
      },
      onEachFeature: (feature, layer) => {
        layer.bindPopup(
          `<h3 class="popup-title">${feature.properties?.name || "Estacion FONAG"}</h3><p class="popup-copy">${feature.properties?.summary || "Estacion hidrometeorologica disponible."}</p>`
        );
        layer.bindTooltip(
          `${feature.properties?.code || "EST"} | ${feature.properties?.stationKind || "hidromet"} | ${feature.properties?.annualMetricLabel || ""}`,
          { sticky: true }
        );
      },
    }).addTo(mapState.map);
  }

  if (mapState.fieldEvidenceHistoryLayer?.bringToBack) {
    mapState.fieldEvidenceHistoryLayer.bringToBack();
  }
  if (mapState.fieldEvidenceSensitiveLayer?.bringToFront) {
    mapState.fieldEvidenceSensitiveLayer.bringToFront();
  }
  if (mapState.fieldEvidenceSectorLayer?.bringToFront) {
    mapState.fieldEvidenceSectorLayer.bringToFront();
  }
  if (mapState.fieldEvidenceStationLayer?.bringToFront) {
    mapState.fieldEvidenceStationLayer.bringToFront();
  }
  if (mapState.planningCandidatesLayer?.bringToFront) {
    mapState.planningCandidatesLayer.bringToFront();
  }
  if (state.aiGeoData?.mode === "territorial") {
    bringAiGeoOverlayToFront();
  }
}

