function ensurePlot(message, silent = false) {
  if (state.currentPlot) {
    return true;
  }
  if (!silent) {
    setStatus(message);
  }
  return false;
}

function updateMapSummary(force = false) {
  if (!force) {
    scheduleUiTask("map-summary", () => updateMapSummary(true));
    return;
  }

  renderWorkflowGuide();

  if (isTerritorialRoute()) {
    const planning = state.planningData;
    const fodaCame = state.fodaCameData;
    const aiGeo = state.aiGeoData;
    const landChange = state.landChangeData;
    const hydrology = state.hydrologyData;
    const officialData = state.officialData.planificacion?.activeLayerCount ? state.officialData.planificacion : null;
    const imageryProfile = planning?.imageryProfile || getPlanningImageryProfile();
    const landChangePeriod = landChange?.period || getLandChangePeriodProfile();
    const landChangeScenario = landChange?.scenario || getLandChangeScenarioProfile();
    const landChangeLens = landChange?.lens || getLandChangeLensProfile();
    const hydrologyClimate = hydrology?.climate || getHydrologyClimateProfile();
    const hydrologyHorizon = hydrology?.horizon || getHydrologyHorizonProfile();
    const hydrologyDemand = hydrology?.demand || getHydrologyDemandProfile();
    const showFodaCame = state.territorialFocus === "fodaCame" && fodaCame;
    const showAiGeo = state.territorialFocus === "aiGeo" && aiGeo?.mode === "territorial";
    const showLandChange = state.territorialFocus === "landChange" && landChange;
    const showHydrology = state.territorialFocus === "hydrology" && hydrology;
    const showOfficial = state.territorialFocus === "official" && officialData;
    setTextIfChanged(dom.overlayIndex, planning ? "Aptitud" : imageryProfile.shortLabel);
    renderMapBadges();
    if (showAiGeo) {
      setTextIfChanged(dom.overlayIndex, "IA");
      setTextIfChanged(dom.mapTitle, `IA territorial sobre ${aiGeo.context.scopeLabel}`);
      setTextIfChanged(
        dom.mapSubtitle,
        `${aiGeo.summary.dominantClassLabel}. ${aiGeo.summary.changeHotspotCount} hotspots, ${aiGeo.summary.alertCount} alertas y ${formatPlanning3dCount(aiGeo.summary.buildings3dCount)} construcciones 3D.`
      );
    } else if (showFodaCame) {
      setTextIfChanged(dom.overlayIndex, "FODA");
      setTextIfChanged(dom.mapTitle, `Analisis FODA + CAME sobre ${fodaCame.context.scopeLabel}`);
      setTextIfChanged(
        dom.mapSubtitle,
        `${fodaCame.summary.dominantActionLabel}. ${fodaCame.priorityZones.length} zonas y ${formatLandChangeHa(fodaCame.summary.priorityAreaHa)} ha priorizadas.`
      );
    } else if (showLandChange) {
      setTextIfChanged(dom.overlayIndex, "Huella");
      setTextIfChanged(dom.mapTitle, `Transformacion del suelo rural sobre ${landChange.context.scopeLabel}`);
      setTextIfChanged(
        dom.mapSubtitle,
        `${landChangePeriod.shortLabel} · ${landChangeScenario.label} · ${landChangeLens.label}. ${formatLandChangeHa(landChange.summary.transformedHa)} ha transformadas.`
      );
    } else if (showHydrology) {
      setTextIfChanged(dom.overlayIndex, "Balance");
      setTextIfChanged(dom.mapTitle, `Disponibilidad hidrica sobre ${hydrology.context.scopeLabel}`);
      setTextIfChanged(
        dom.mapSubtitle,
        `${hydrologyClimate.shortLabel} · ${hydrologyHorizon.shortLabel} · ${hydrologyDemand.shortLabel}. Balance ${hydrology.summary.balanceHm3 >= 0 ? "+" : ""}${formatHydrologyHm3(hydrology.summary.balanceHm3)} hm3/anio y ${hydrology.prioritySectors.length} prioridades.`
      );
    } else if (showOfficial) {
      setTextIfChanged(dom.overlayIndex, "Oficial");
      setTextIfChanged(dom.mapTitle, `Fuentes oficiales sobre ${officialData.scopeLabel}`);
      setTextIfChanged(
        dom.mapSubtitle,
        `${officialData.activeLayerCount} capas activas, ${officialData.pointCount} servicios y ${officialData.lineCount + officialData.areaCount} corredores o superficies visibles.`
      );
    } else if (planning) {
      setTextIfChanged(dom.mapTitle, `${planning.program.longLabel} sobre ${planning.context.scopeLabel}`);
      setTextIfChanged(
        dom.mapSubtitle,
        `${planning.imageryProfile.shortLabel} · ${planning.horizon.label} · ${planning.scenario.label}. ${planning.candidates.length} candidatos y cobertura ${planning.serviceCoverage.overallCoverage}%.`
      );
    } else if (fodaCame) {
      setTextIfChanged(dom.overlayIndex, "FODA");
      setTextIfChanged(dom.mapTitle, "Estrategia territorial lista");
      setTextIfChanged(dom.mapSubtitle, `${fodaCame.summary.dominantSwotLabel} · ${fodaCame.summary.dominantActionLabel}. ${fodaCame.priorityZones.length} zonas visibles.`);
    } else if (aiGeo?.mode === "territorial") {
      setTextIfChanged(dom.overlayIndex, "IA");
      setTextIfChanged(dom.mapTitle, "Lectura IA territorial lista");
      setTextIfChanged(dom.mapSubtitle, `${aiGeo.summary.dominantClassLabel} · ${aiGeo.summary.alertCount} alertas sobre ${aiGeo.context.scopeLabel}.`);
    } else if (hydrology) {
      setTextIfChanged(dom.overlayIndex, "Balance");
      setTextIfChanged(dom.mapTitle, "Estudio hidrico de Mejia listo");
      setTextIfChanged(dom.mapSubtitle, `${hydrology.climate.shortLabel} · ${hydrology.horizon.shortLabel} · ${hydrology.demand.shortLabel}. Balance ${hydrology.summary.balanceHm3 >= 0 ? "+" : ""}${formatHydrologyHm3(hydrology.summary.balanceHm3)} hm3/anio.`);
    } else if (landChange) {
      setTextIfChanged(dom.overlayIndex, "Huella");
      setTextIfChanged(dom.mapTitle, "Estudio de transformacion del suelo listo");
      setTextIfChanged(dom.mapSubtitle, `${landChange.period.shortLabel} · ${formatLandChangeHa(landChange.summary.transformedHa)} ha transformadas · ${landChange.summary.hotspotLabel}.`);
    } else if (officialData) {
      setTextIfChanged(dom.overlayIndex, "Oficial");
      setTextIfChanged(dom.mapTitle, `Fuentes oficiales sobre ${officialData.scopeLabel}`);
      setTextIfChanged(
        dom.mapSubtitle,
        `${officialData.activeLayerCount} capas listas, ${officialData.pointCount} servicios y ${officialData.totalFeatures} referencias oficiales visibles.`
      );
    } else {
      setTextIfChanged(dom.mapTitle, "Planificacion territorial lista");
      setTextIfChanged(dom.mapSubtitle, `Empieza por aptitud, huella, agua, estrategia o 3D sobre ${getTerritorialAreaProfile().scopeLabel}.`);
    }
    return;
  }

  syncAgronomyBaseLayerOpacity();

  if (isGpsTrackingActive() || state.agronomyOutputs.gps) {
    const activeDevice = state.agronomyOutputs.gps?.activeDevice || state.gpsTracking.lastDeviceSnapshot;
    const geofenceSummary = state.gpsTracking.geofence?.summary || null;
    setTextIfChanged(dom.overlayIndex, "GPS");
    setTextIfChanged(dom.mapTitle, activeDevice?.label ? `Seguimiento GPS: ${activeDevice.label}` : "Seguimiento GPS en vivo");
    setTextIfChanged(dom.mapSubtitle, activeDevice
      ? `Ultima senal ${formatGpsSignalAge(activeDevice.timestamp)}.${geofenceSummary ? (geofenceSummary.outsideCount ? ` ${geofenceSummary.outsideCount} fuera del corredor.` : " Dentro del corredor.") : ""}`
      : `Base lista para recibir GPS.${geofenceSummary ? " Corredor cargado." : ""}`);
    renderMapBadges();
    return;
  }

  const aiGeo = state.aiGeoData;
  if (aiGeo?.mode === "agronomia") {
    setTextIfChanged(dom.overlayIndex, "IA");
    setTextIfChanged(dom.mapTitle, `IA agronomica sobre ${aiGeo.context.scopeLabel}`);
    setTextIfChanged(
      dom.mapSubtitle,
      `${aiGeo.summary.dominantClassLabel}. ${aiGeo.summary.changeHotspotCount} cambios, ${aiGeo.summary.alertCount} alertas y confianza ${aiGeo.summary.confidenceScore}/100.`
    );
    renderMapBadges();
    return;
  }

  const agronomyOfficial = state.officialData.agronomia?.activeLayerCount ? state.officialData.agronomia : null;

  const image = getSelectedImage();
  const sensor = image ? getSensorForImage(image) : getActiveSensor();
  const analysis = getRenderableAnalysis(image);
  const compareImage = getCompareImage();
  const changeAnalysis = getRenderableChangeAnalysis(image, compareImage);
  const previewLabel = getSceneLayerStatusLabel(image || sensor.id, state.sceneLayerKind);
  setTextIfChanged(dom.overlayIndex, indexConfig[state.selectedIndex].label);

  if (dom.mapStage) {
    dom.mapStage.dataset.sensor = sensor.id;
  }

  if (!image) {
    setTextIfChanged(dom.mapTitle, agronomyOfficial ? `Fuentes oficiales sobre ${agronomyOfficial.scopeLabel}` : "No hay escena activa");
    renderMapBadges();
    setTextIfChanged(
      dom.mapSubtitle,
      agronomyOfficial
        ? `${agronomyOfficial.activeLayerCount} capas activas, ${agronomyOfficial.lineCount} trazos de agua/riego y ${agronomyOfficial.areaCount} superficies oficiales visibles.`
        : `Abre Imagenes o usa un lote demo sobre ${getAgronomyAreaProfile().scopeLabel}.`
    );
    return;
  }

  renderMapBadges(image, compareImage, previewLabel);

  if (!state.satelliteLayersEnabled) {
    setTextIfChanged(dom.mapTitle, "Capas satelitales desactivadas");
    setTextIfChanged(dom.mapSubtitle, "Solo base y capas vectoriales.");
    return;
  }

  if (analysis) {
    if (state.surfaceMode === "change" && changeAnalysis && compareImage) {
      const delta = changeAnalysis.summary[state.selectedIndex];
      setTextIfChanged(dom.mapTitle, `Cambio ${indexConfig[state.selectedIndex].label} sobre ${analysis.context.scopeLabel}`);
      setTextIfChanged(dom.mapSubtitle, `${changeAnalysis.direction} · delta medio ${formatDelta(delta.mean, indexConfig[state.selectedIndex])}.`);
      return;
    }

    const stats = analysis.summary[state.selectedIndex];
    const modeLabel = compareImage
      ? `vs ${localeDate.format(new Date(`${compareImage.date}T00:00:00`))}`
      : analysis.processingMode === "backend"
        ? "proxy local"
        : image.source === "real"
          ? "AOI local"
          : "motor demo";
    setTextIfChanged(dom.mapTitle, `${indexConfig[state.selectedIndex].label} sobre ${analysis.context.scopeLabel}`);
    const outOfScaleNote = isSceneOutOfScaleForUrbanZoom(image)
      ? " Base satelital activa para detalle fino."
      : "";
    setTextIfChanged(dom.mapSubtitle, `Media ${formatValue(stats.mean, indexConfig[state.selectedIndex])} · ${modeLabel}.${outOfScaleNote}`);
    return;
  }

  if (image.source === "real") {
    setTextIfChanged(dom.mapTitle, `Escena real ${image.title}`);
    setTextIfChanged(dom.mapSubtitle, "Preparando escena y AOI.");
    return;
  }

  setTextIfChanged(dom.mapTitle, `${indexConfig[state.selectedIndex].label} sobre ${image.title}`);
  setTextIfChanged(dom.mapSubtitle, image.note);
}

function renderMapBadges(image = null, compareImage = null, previewLabel = "sin capa") {
  if (!dom.mapBadges) {
    return;
  }

  if (isTerritorialRoute()) {
    const planning = state.planningData;
    const fodaCame = state.fodaCameData;
    const aiGeo = state.aiGeoData;
    const landChange = state.landChangeData;
    const hydrology = state.hydrologyData;
    const imageryProfile = planning?.imageryProfile || getPlanningImageryProfile();
    const landChangePeriod = landChange?.period || getLandChangePeriodProfile();
    const landChangeScenario = landChange?.scenario || getLandChangeScenarioProfile();
    const climate = hydrology?.climate || getHydrologyClimateProfile();
    const horizon = hydrology?.horizon || getHydrologyHorizonProfile();
    const badges = (state.territorialFocus === "aiGeo" && aiGeo?.mode === "territorial")
      ? [
          {
            tone: "analysis",
            label: "IA territorial",
          },
          {
            tone: "neutral",
            label: aiGeo.summary.dominantClassLabel,
          },
          {
            tone: aiGeo.summary.confidenceScore >= 80
              ? "exact"
              : aiGeo.summary.confidenceScore >= 64
                ? "preview"
                : "compare",
            label: `${aiGeo.summary.confidenceScore}/100`,
          },
          {
            tone: "neutral",
            label: `${aiGeo.summary.changeHotspotCount} hotspots`,
          },
          {
            tone: "neutral",
            label: `${aiGeo.summary.alertCount} alertas`,
          },
          {
            tone: "neutral",
            label: `${formatPlanning3dCount(aiGeo.summary.buildings3dCount)} 3D`,
          },
        ]
      : state.territorialFocus === "fodaCame" && fodaCame
      ? [
          {
            tone: "analysis",
            label: "FODA+CAME",
          },
          {
            tone: "neutral",
            label: fodaCame.summary.dominantSwotLabel,
          },
          {
            tone: "neutral",
            label: fodaCame.summary.dominantActionLabel,
          },
          {
            tone: fodaCame.summary.overallScore >= 72
              ? "exact"
              : fodaCame.summary.overallScore >= 58
                ? "preview"
                : "compare",
            label: `${fodaCame.priorityZones.length} zonas`,
          },
          {
            tone: "neutral",
            label: `${formatLandChangeHa(fodaCame.summary.priorityAreaHa)} ha`,
          },
        ]
      : state.territorialFocus === "landChange" && landChange
      ? [
          {
            tone: "analysis",
            label: "Huella",
          },
          {
            tone: "neutral",
            label: landChangePeriod.shortLabel,
          },
          {
            tone: "neutral",
            label: landChangeScenario.shortLabel,
          },
          {
            tone: landChange.summary.meanScore >= 74
              ? "compare"
              : landChange.summary.meanScore >= 58
                ? "preview"
                : "exact",
            label: landChange.summary.riskLabel,
          },
          {
            tone: "neutral",
            label: `${formatLandChangeHa(landChange.summary.riskHa)} ha en vigilancia`,
          },
        ]
      : state.territorialFocus === "hydrology" && hydrology
      ? [
          {
            tone: "analysis",
            label: "Hidrica",
          },
          {
            tone: "neutral",
            label: climate.shortLabel,
          },
          {
            tone: "neutral",
            label: horizon.shortLabel,
          },
          {
            tone: getHydrologyBalanceTone(hydrology.summary.balanceHm3) === "surplus"
              ? "exact"
              : getHydrologyBalanceTone(hydrology.summary.balanceHm3) === "watch"
                ? "preview"
                : "compare",
            label: hydrology.summary.balanceLabel,
          },
          {
            tone: "neutral",
            label: `${hydrology.prioritySectors.length} prioridades`,
          },
        ]
      : state.territorialFocus === "official" && officialData
      ? [
          {
            tone: "analysis",
            label: "Oficial",
          },
          {
            tone: "neutral",
            label: `${officialData.sourceCount} fuentes`,
          },
          {
            tone: "neutral",
            label: `${officialData.pointCount} servicios`,
          },
          {
            tone: "preview",
            label: `${officialData.lineCount} corredores`,
          },
          {
            tone: "neutral",
            label: `${officialData.areaCount} superficies`,
          },
        ]
      : [
          {
            tone: "analysis",
            label: "Territorial",
          },
          {
            tone: "neutral",
            label: imageryProfile.shortLabel,
          },
          {
            tone: "neutral",
            label: imageryProfile.spatialLabel,
          },
          planning
            ? {
                tone: "neutral",
                label: "Halos + isocronas",
              }
            : hydrology
              ? {
                  tone: "neutral",
                  label: "Vigilancia",
                }
              : landChange
                ? {
                    tone: "neutral",
                    label: "Calor",
                  }
                : {
                    tone: "muted",
                    label: "Listo",
                  },
          planning
            ? {
                tone: "analysis",
                label: `Plan ${planning.program.label}`,
              }
              : hydrology
              ? {
                  tone: "analysis",
                  label: `Agua ${hydrology.climate.shortLabel}`,
                }
              : landChange
                ? {
                    tone: "analysis",
                    label: `Huella ${landChange.period.shortLabel}`,
                  }
              : {
                  tone: "muted",
                  label: "Sin escenario",
                },
          planning
            ? {
                tone: "neutral",
                label: "Restricciones + sol",
              }
            : null,
        ].filter(Boolean);
    setHtmlIfChanged(dom.mapBadges, badges
      .map((badge) => `<span class="map-badge ${badge.tone}">${badge.label}</span>`)
      .join(""));
    return;
  }

  if (isGpsTrackingActive() || state.agronomyOutputs.gps) {
    const activeDevice = state.agronomyOutputs.gps?.activeDevice || state.gpsTracking.lastDeviceSnapshot;
    const geofenceSummary = state.gpsTracking.geofence?.summary || null;
    const badges = [
      {
        tone: "analysis",
        label: activeDevice ? "GPS en vivo" : "GPS listo",
      },
      {
        tone: "neutral",
        label: "Base Esri",
      },
      {
        tone: "muted",
        label: "Sin Sentinel",
      },
      {
        tone: "muted",
        label: "Sin grilla NDVI",
      },
    ];
    if (geofenceSummary) {
      badges.push({
        tone: geofenceSummary.outsideCount ? "compare" : "neutral",
        label: geofenceSummary.outsideCount
          ? `${geofenceSummary.outsideCount} fuera de ruta`
          : "Corredor activo",
      });
    }
    if (activeDevice?.accuracyM) {
      badges.push({
        tone: "neutral",
        label: `Precision ${Math.round(Number(activeDevice.accuracyM))} m`,
      });
    }
    setHtmlIfChanged(dom.mapBadges, badges
      .map((badge) => `<span class="map-badge ${badge.tone}">${badge.label}</span>`)
      .join(""));
    return;
  }

  if (state.aiGeoData?.mode === "agronomia") {
    const aiGeo = state.aiGeoData;
    const badges = [
      {
        tone: "analysis",
        label: "IA agronomica",
      },
      {
        tone: `sensor sensor-${getSensorForImage(aiGeo.image).id}`,
        label: getSensorForImage(aiGeo.image).label,
      },
      {
        tone: aiGeo.summary.confidenceScore >= 80
          ? "exact"
          : aiGeo.summary.confidenceScore >= 64
            ? "preview"
            : "compare",
        label: `${aiGeo.summary.confidenceScore}/100`,
      },
      {
        tone: "neutral",
        label: aiGeo.summary.dominantClassLabel,
      },
      {
        tone: "neutral",
        label: `${aiGeo.summary.changeHotspotCount} cambios`,
      },
      {
        tone: "neutral",
        label: `${aiGeo.summary.alertCount} alertas`,
      },
    ];
    setHtmlIfChanged(dom.mapBadges, badges
      .map((badge) => `<span class="map-badge ${badge.tone}">${badge.label}</span>`)
      .join(""));
    return;
  }

  if (!image) {
    const sensor = getActiveSensor();
    const officialBadge = state.officialData.agronomia?.activeLayerCount
      ? `<span class="map-badge analysis">Oficial ${state.officialData.agronomia.activeLayerCount}</span>`
      : "";
    const planningBadge = state.planningData
      ? `<span class="map-badge analysis">Plan ${state.planningData.program.label}</span>`
      : "";
    setHtmlIfChanged(dom.mapBadges, `
      <span class="map-badge sensor sensor-${sensor.id}">${sensor.label}</span>
      <span class="map-badge muted">Sin escena</span>
      ${officialBadge}
      ${planningBadge}
    `);
    return;
  }

  const rasterTone = state.sceneLayerKind === "exact"
    ? "exact"
    : state.sceneLayerKind === "loading"
      ? "loading"
      : state.sceneLayerKind === "preview" || state.sceneLayerKind === "footprint"
        ? "preview"
        : "muted";
  const sensor = getSensorForImage(image);
  const badges = [
    {
      tone: `sensor sensor-${sensor.id}`,
      label: sensor.label,
    },
    {
      tone: "neutral",
      label: sensor.sceneResolutionLabel,
    },
    {
      tone: "neutral",
      label: localeDate.format(new Date(`${image.date}T00:00:00`)),
    },
    {
      tone: "neutral",
      label: getSceneMetaLabel(image),
    },
    {
      tone: state.satelliteLayersEnabled ? rasterTone : "muted",
      label: state.satelliteLayersEnabled
        ? (state.showScenePreview ? previewLabel : "capa oculta")
        : "capas apagadas",
    },
    {
      tone: state.satelliteLayersEnabled && state.showAnalysisOverlay ? "analysis" : "muted",
      label: state.satelliteLayersEnabled
        ? (state.showAnalysisOverlay ? "analisis visible" : "solo escena")
        : "analisis apagado",
    },
  ];

  if (compareImage) {
    badges.push({
      tone: "compare",
      label: `Comp ${localeDate.format(new Date(`${compareImage.date}T00:00:00`))}`,
    });
  }

  if (state.planningData) {
    badges.push({
      tone: "analysis",
      label: `Plan ${state.planningData.program.label}`,
    });
  }

  if (state.officialData.agronomia?.activeLayerCount) {
    badges.push({
      tone: "analysis",
      label: `Oficial ${state.officialData.agronomia.activeLayerCount}`,
    });
  }

  setHtmlIfChanged(dom.mapBadges, badges
    .map((badge) => `<span class="map-badge ${badge.tone}">${badge.label}</span>`)
    .join(""));
}

function getAgronomyMapMaxZoomForBase(baseId = state.baseLayer) {
  return agronomyMapZoomLimits[baseId] || agronomyMapZoomLimits.satellite;
}

function clampAgronomyMapZoomForBase(baseId = state.baseLayer) {
  if (!mapState.map) {
    return getAgronomyMapMaxZoomForBase(baseId);
  }

  const maxZoom = getAgronomyMapMaxZoomForBase(baseId);
  mapState.map.setMaxZoom(maxZoom);
  if (mapState.map.getZoom() > maxZoom) {
    mapState.map.setZoom(maxZoom, {
      animate: false,
    });
  }
  return maxZoom;
}

function getSafeAgronomyMapZoom(zoom, baseId = state.baseLayer) {
  const nextZoom = Number.isFinite(Number(zoom)) ? Number(zoom) : getAgronomyAreaMapView().zoom;
  return Math.min(nextZoom, getAgronomyMapMaxZoomForBase(baseId));
}

function setBaseLayer(baseId, initial = false, options = {}) {
  const settings = {
    silent: false,
    skipSceneRender: false,
    ...options,
  };
  const gpsBaseLocked = state.entryRoute === "agronomia" && isGpsTrackingActive();
  const requestedBaseId = gpsBaseLocked ? "satellite" : baseId;
  let resolvedBaseId = mapState.baseLayers[requestedBaseId] ? requestedBaseId : "satellite";
  let nextLayer = mapState.baseLayers[resolvedBaseId];

  if (!nextLayer) {
    resolvedBaseId = "satellite";
    nextLayer = mapState.baseLayers.satellite;
  }

  state.baseLayer = resolvedBaseId;
  dom.baseButtons.forEach((button) => {
    button.classList.toggle("active", button.dataset.base === resolvedBaseId);
  });

  if (!mapState.map) {
    return;
  }

  if (mapState.activeBaseLayer) {
    mapState.map.removeLayer(mapState.activeBaseLayer);
  }

  mapState.activeBaseLayer = nextLayer;
  mapState.activeBaseLayer.addTo(mapState.map);
  clampAgronomyMapZoomForBase(resolvedBaseId);
  applyEsriSatelliteResolution(false);
  syncAgronomyBaseLayerOpacity();
  syncEsriResolutionButtons();
  syncSatelliteSuperResolution();
  if (gpsBaseLocked) {
    clearGpsBlockingImageryLayers();
  }

  if (!initial && state.entryRoute === "agronomia" && getSelectedImage() && !settings.skipSceneRender && !gpsBaseLocked) {
    renderSentinelOverlay();
  }

  if (!initial && !settings.silent) {
    if (gpsBaseLocked && baseId !== "satellite") {
      setStatus("Durante seguimiento GPS se mantiene la imagen satelital base Esri para evitar capas confusas.");
      return;
    }
    const baseLabel = resolvedBaseId === "satellite" ? "Esri HR" : "Calles";
    const zoomNote = resolvedBaseId === "satellite"
      ? ` Zoom profundo ${getAgronomyMapMaxZoomForBase(resolvedBaseId)} con teselas nativas Esri z18 para mayor detalle urbano.`
      : "";
    setStatus(`Mapa base cambiado a ${baseLabel}.${zoomNote}`);
  }
}

function setStatus(text) {
  dom.statusBar.textContent = text;
}

function isSatelliteVisualBase(baseId = state.baseLayer) {
  return baseId === "satellite";
}

function getSurfaceConfig() {
  if (state.surfaceMode === "change" && getRenderableChangeAnalysis()) {
    return getChangeConfig(state.selectedIndex);
  }
  return indexConfig[state.selectedIndex];
}

function getChangeConfig(indexKey) {
  const ranges = {
    NDVI: 0.28,
    NDWI: 0.22,
    NDMI: 0.22,
    NDRE: 0.2,
    MSAVI: 0.28,
    VV: 3.2,
    VH: 3.6,
    RVI: 0.24,
    VH_VV: 0.18,
  };
  return {
    label: `Delta ${indexConfig[indexKey].label}`,
    min: -(ranges[indexKey] || 0.2),
    max: ranges[indexKey] || 0.2,
    unit: "",
    colors: ["#9f4a36", "#d69a64", "#f6f1e7", "#88c2b0", "#1d6b49"],
    description: `Cambio temporal de ${indexConfig[indexKey].label} entre la escena activa y la comparada.`,
  };
}

function formatLegendStat(value, config) {
  if (state.surfaceMode === "change" && getRenderableChangeAnalysis()) {
    return formatDelta(value, config);
  }
  return formatValue(value, config);
}

function formatDelta(value, config) {
  const digits = Math.abs(config.max) <= 1 ? 2 : 1;
  const prefix = value > 0 ? "+" : "";
  return `${prefix}${value.toFixed(digits)}${config.unit || ""}`;
}

function getStrongestChangeIndex(summary) {
  return Object.keys(summary)
    .map((indexKey) => ({ indexKey, score: Math.abs(summary[indexKey].mean) }))
    .sort((a, b) => b.score - a.score)[0]?.indexKey || getActiveSensor().defaultIndex;
}

function dayDiff(dateA, dateB) {
  const first = new Date(`${dateA}T00:00:00Z`);
  const second = new Date(`${dateB}T00:00:00Z`);
  return Math.round((first.getTime() - second.getTime()) / 86400000);
}

function getSceneAgeDays(image) {
  const reference = image.datetime || `${image.date}T00:00:00Z`;
  const milliseconds = Date.now() - new Date(reference).getTime();
  return Math.max(0, Math.round(milliseconds / 86400000));
}

function estimateSceneConfidence(image, freshnessDays = getSceneAgeDays(image)) {
  const sensor = getSensorForImage(image);
  const cloudPenalty = sensor.cloudEnabled
    ? Number.isFinite(image.cloud)
      ? image.cloud * 0.55
      : 18
    : 6;
  const freshnessPenalty = Math.min(freshnessDays * (sensor.id === "sentinel1" ? 1.1 : 1.4), sensor.id === "sentinel1" ? 18 : 24);
  const sourceBonus = image.source === "real" ? 12 : 0;
  const sensorBonus = sensor.id === "sentinel1" ? 4 : sensor.id === "landsat" ? 2 : 0;
  return Math.round(clamp(92 - cloudPenalty - freshnessPenalty + sourceBonus + sensorBonus, 28, 98));
}

function formatAgeLabel(days) {
  if (!Number.isFinite(days) || days <= 0) {
    return "Hoy";
  }
  if (days === 1) {
    return "Hace 1 d";
  }
  return `Hace ${days} d`;
}

function getFeatureKey(feature) {
  return JSON.stringify(feature?.geometry || feature || null);
}

function deriveIndexValue({ lon, lat, seed, base, config }) {
  const raw = base + pseudoNoise(lon * 5, lat * 7, seed) * 0.13 + pseudoNoise(lat * 11, lon * 3, seed + 9) * 0.06;
  return clamp(raw, config.min, config.max);
}

function pseudoNoise(x, y, seed) {
  const value = Math.sin((x + seed) * 12.9898 + (y - seed) * 78.233) * 43758.5453;
  return (value - Math.floor(value)) * 2 - 1;
}

function clamp(value, min, max) {
  return Math.min(Math.max(value, min), max);
}

function interpolateColor(value, min, max, colors) {
  const normalized = clamp((value - min) / (max - min || 1), 0, 1);
  const steps = colors.map(hexToRgb);
  const scaled = normalized * (steps.length - 1);
  const index = Math.min(Math.floor(scaled), steps.length - 2);
  const local = scaled - index;
  const start = steps[index];
  const end = steps[index + 1];
  const mix = {
    r: Math.round(start.r + (end.r - start.r) * local),
    g: Math.round(start.g + (end.g - start.g) * local),
    b: Math.round(start.b + (end.b - start.b) * local),
  };
  return `rgb(${mix.r}, ${mix.g}, ${mix.b})`;
}

function hexToRgb(hex) {
  const clean = hex.replace("#", "");
  return {
    r: Number.parseInt(clean.slice(0, 2), 16),
    g: Number.parseInt(clean.slice(2, 4), 16),
    b: Number.parseInt(clean.slice(4, 6), 16),
  };
}

function formatValue(value, config) {
  const digits = config.max <= 1 ? 2 : 1;
  return `${value.toFixed(digits)}${config.unit}`;
}

function cardinalFromAngle(angle) {
  const directions = ["Norte", "Noreste", "Este", "Sureste", "Sur", "Suroeste", "Oeste", "Noroeste"];
  const normalized = ((angle % 360) + 360) % 360;
  const index = Math.round(normalized / 45) % directions.length;
  return directions[index];
}

function formatDateInput(value) {
  return value.toISOString().slice(0, 10);
}

function normalizeDateRange(start, end) {
  if (!start && !end) {
    const today = formatDateInput(new Date());
    return { start: today, end: today };
  }

  if (!start) {
    return { start: end, end };
  }

  if (!end) {
    return { start, end: start };
  }

  return start <= end ? { start, end } : { start: end, end: start };
}

function getSearchArea() {
  return state.currentPlot || getAgronomyAreaFeature();
}

function getSentinelSearchArea() {
  return getSearchArea();
}

function formatCloudValue(value) {
  if (!Number.isFinite(value)) {
    return "s/d";
  }
  return `${Number(value.toFixed(1))}%`;
}

function formatDistanceKm(value) {
  if (!Number.isFinite(value)) {
    return "s/d";
  }
  if (value < 1) {
    return `${Math.round(value * 1000)} m`;
  }
  return `${value.toFixed(1)} km`;
}

function formatFacilityTypeLabel(serviceType) {
  if (serviceType === "escuela") {
    return "Escuela";
  }
  if (serviceType === "hospital") {
    return "Salud";
  }
  if (serviceType === "centro-salud") {
    return "Centro de salud";
  }
  if (serviceType === "social") {
    return "Servicio social";
  }
  if (serviceType === "institucional") {
    return "Presencia institucional";
  }
  if (serviceType === "equipamiento") {
    return "Equipamiento";
  }
  return "Servicio";
}

function formatPlatform(platform, fallback = getActiveSensor().label) {
  if (!platform) {
    return fallback;
  }

  if (/^landsat-/i.test(platform)) {
    return platform.replace(/^landsat-(\d+)/i, "Landsat $1");
  }

  return platform
    .replace(/^sentinel-/i, "Sentinel-")
    .replace(/([0-9])([a-z])/i, (_, number, letter) => `${number}${letter.toUpperCase()}`);
}

function formatOrbitState(orbitState) {
  if (!orbitState) {
    return "Orbita s/d";
  }
  return orbitState === "ascending"
    ? "Ascendente"
    : orbitState === "descending"
      ? "Descendente"
      : orbitState;
}

function getWizardBiasBySensor(sensorId) {
  if (sensorId === "landsat") {
    return {
      Monitoreo: { NDVI: 0.02, NDMI: 0.015, NDWI: 0.01, MSAVI: 0 },
      Siembra: { NDVI: -0.01, NDMI: 0.02, NDWI: 0.01, MSAVI: 0.02 },
      Cosecha: { NDVI: -0.02, NDMI: -0.01, NDWI: -0.01, MSAVI: 0.02 },
      Diagnostico: { NDVI: -0.01, NDMI: 0.02, NDWI: 0.02, MSAVI: 0.01 },
    };
  }

  if (sensorId === "sentinel1") {
    return {
      Monitoreo: { RVI: 0.03, VH_VV: 0.02, VV: 0.5, VH: 0.3 },
      Siembra: { RVI: -0.01, VH_VV: 0.03, VV: 0.2, VH: 0.2 },
      Cosecha: { RVI: -0.03, VH_VV: -0.01, VV: -0.4, VH: -0.5 },
      Diagnostico: { RVI: -0.02, VH_VV: 0.04, VV: 0.6, VH: 0.5 },
    };
  }

  return {
    Monitoreo: { NDVI: 0.02, NDWI: 0.01, NDRE: 0.01, MSAVI: 0 },
    Siembra: { NDVI: -0.01, NDWI: 0.02, NDRE: 0, MSAVI: 0.02 },
    Cosecha: { NDVI: -0.02, NDWI: -0.01, NDRE: 0.03, MSAVI: 0.01 },
    Diagnostico: { NDVI: -0.01, NDWI: 0.02, NDRE: 0.02, MSAVI: 0 },
  };
}

function getZoneDeltaThreshold(indexKey) {
  const thresholdMap = {
    NDVI: 0.04,
    NDWI: 0.035,
    NDMI: 0.035,
    NDRE: 0.03,
    MSAVI: 0.04,
    VV: 0.8,
    VH: 0.9,
    RVI: 0.05,
    VH_VV: 0.04,
  };
  return thresholdMap[indexKey] || 0.04;
}

function deriveBetaIndicesFromScene(sceneId, cloudCover, sensorId = state.activeSensorId) {
  const cloudPenalty = Number.isFinite(cloudCover) ? cloudCover / 100 : 0.25;
  const seed = Array.from(sceneId || "scene").reduce((total, char) => total + char.charCodeAt(0), 0);

  if (sensorId === "landsat") {
    const base = clamp(0.68 - cloudPenalty * 0.18 + pseudoNoise(seed, cloudPenalty, 13) * 0.05, 0.24, 0.82);
    return {
      NDVI: clamp(base, 0.18, 0.9),
      NDMI: clamp(0.16 - cloudPenalty * 0.1 + pseudoNoise(seed, cloudPenalty, 17) * 0.05, -0.08, 0.42),
      NDWI: clamp(0.1 - cloudPenalty * 0.08 + pseudoNoise(seed, cloudPenalty, 19) * 0.04, -0.12, 0.32),
      MSAVI: clamp(base - 0.07 + pseudoNoise(seed, cloudPenalty, 23) * 0.04, 0.16, 0.82),
    };
  }

  if (sensorId === "sentinel1") {
    const rvi = clamp(0.5 + pseudoNoise(seed, cloudPenalty, 29) * 0.12 + pseudoNoise(seed, cloudPenalty, 31) * 0.05, 0.18, 0.86);
    const ratio = clamp(0.42 + pseudoNoise(seed, cloudPenalty, 37) * 0.09, 0.14, 0.76);
    const vv = clamp(-11.4 + pseudoNoise(seed, cloudPenalty, 41) * 2.4 - ratio * 1.6, -20.8, -6.2);
    const vh = clamp(vv - 6.2 + pseudoNoise(seed, cloudPenalty, 43) * 1.7, -27.8, -11.4);
    return {
      RVI: rvi,
      VH_VV: ratio,
      VV: vv,
      VH: vh,
    };
  }

  const base = clamp(0.74 - cloudPenalty * 0.22 + pseudoNoise(seed, cloudPenalty, 3) * 0.04, 0.28, 0.82);

  return {
    NDVI: clamp(base, 0.2, 0.92),
    NDWI: clamp(0.2 - cloudPenalty * 0.08 + pseudoNoise(seed, cloudPenalty, 5) * 0.05, -0.12, 0.42),
    NDRE: clamp(base - 0.23 + pseudoNoise(seed, cloudPenalty, 7) * 0.04, 0.12, 0.62),
    MSAVI: clamp(base - 0.05 + pseudoNoise(seed, cloudPenalty, 11) * 0.04, 0.18, 0.86),
  };
}

function layerKey(layerId) {
  return `${layerId}Layer`;
}

function polygonFeature(name, points, properties = {}) {
  return {
    type: "Feature",
    properties: { name, ...properties },
    geometry: {
      type: "Polygon",
      coordinates: [[...points, points[0]]],
    },
  };
}

function lineFeature(name, points, properties = {}) {
  return {
    type: "Feature",
    properties: { name, ...properties },
    geometry: {
      type: "LineString",
      coordinates: points,
    },
  };
}

function pointFeature(name, point, properties = {}) {
  return {
    type: "Feature",
    properties: { name, ...properties },
    geometry: {
      type: "Point",
      coordinates: point,
    },
  };
}
